import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Elements } from '@stripe/react-stripe-js';
import { loadStripe } from '@stripe/stripe-js';
import CheckoutForm from './CheckoutForm';

const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY);

const PaymentSection = ({ onPaymentSuccess }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const { orderId, amount } = location.state || {};

  if (!orderId || !amount) {
    return <div>Error: Missing order information.</div>;
  }

  const handlePaymentSuccess = (paymentResult) => {
    onPaymentSuccess(paymentResult);
    navigate('/thank-you-message'); // Redirect to a success page or wherever needed
  };

  return (
    <Elements stripe={stripePromise}>
      <CheckoutForm orderId={orderId} amount={amount} onPaymentSuccess={handlePaymentSuccess} />
    </Elements>
  );
};

export default PaymentSection;
